class ClientFactory {
    public function getClient(): Client {
        $cfg = $this->configManager->getByNamespace('booking.guzzle_config');
        $username = $this->configManager->getStringOption('booking.wsse_username');
        $password = $this->configManager->getStringOption('booking.wsse_password');

        // Build client config from ConfigManager
        $clientConfig = [];
        foreach ($cfg as $k => $v) {
            $simplified_key = substr($k, strrpos($k, '.') + 1);
            $clientConfig[$simplified_key] = $v;
        }

        // Use HandlerStack for middleware
        $wsse = new WsseAuthMiddleware($username, $password);
        $stack = HandlerStack::create();
        $stack->push($wsse->attach());

        $clientConfig['handler'] = $stack;
        return new Client($clientConfig);
    }
}
```

