class RedisPersistence implements TokenPersistenceInterface {
    private CacheInterface $redisCache;
    private ?string $cacheKey;

    public function withCacheKey(string $cacheKey): self {
        $this->cacheKey = md5($cacheKey);
        return $this;
    }

    public function saveToken(JwtToken $token): void {
        $this->redisCache->set($this->cacheKey, $token);
    }

    public function restoreToken(): ?JwtToken {
        $token = $this->redisCache->get($this->cacheKey);
        return $token ? $token : null;
    }
}
